(window.webpackJsonp=window.webpackJsonp||[]).push([[27],{292:function(v,_,t){"use strict";t.r(_);var a=t(13),s=Object(a.a)({},(function(){var v=this,_=v._self._c;return _("ContentSlotsDistributor",{attrs:{"slot-key":v.$parent.slotKey}},[_("h1",{attrs:{id:"四海八荒"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#四海八荒"}},[v._v("#")]),v._v(" 四海八荒")]),v._v(" "),_("h2",{attrs:{id:"漠北天地"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#漠北天地"}},[v._v("#")]),v._v(" 漠北天地")]),v._v(" "),_("p",[v._v("江南伤情地，金陵苦痛州。既然思念不得了却，那便到漠北的天地一解情伤。匆匆北往，在深夜的高空里飞翔。龙嘉的夜漫长，渐渐日出，东方明亮。满洲皇城里，见那两朝天子，国破家亡。溥仪，贵为天子，身逢乱世，一生如此，常人又能如何？南湖畔，闻凉凉声起，又是一分悲伤。一曲凉凉，道不尽人生沧桑。情彷徨，一路行向北方。北国冰城，观城景，赏江情，何苦寻求，那若有若无的思念？太阳岛上的松鼠，活泼可爱；松花江畔的游鱼，欢呼雀跃。自然的一切，终归是美好的。东北大地上，经历了一个世纪的历史风霜。前赴后继的侵略者们，让那中东铁路洒满中华儿女的汗水。历史的风云变幻之中，那点点思念又有何意义？")]),v._v(" "),_("p",[v._v("西越大兴安岭，便至满洲腹地。呼伦贝尔，中华雄鸡头上那不可缺少的一部分，内蒙大地上璀璨的明珠。草原的天，是湛蓝的；草原的湖，是碧绿的。不同于西边的锡林郭勒，这里没有亮眼的油菜花海，也没有一望无际的草原大漠。中俄边关之所在，让这里多了几分异域风情。那么，便向着那异域进发。却见边关内外，竟是完全不同的景象。后贝加尔的街头，破败凋零；赤塔州里的道路，尘土飞杨。俄罗斯，已不再是当年的毛熊。如今的它，在破落中重整他最后的辉煌。当金发姑娘们成为了国家的大多数，这片土地的未来，从何谈起？")]),v._v(" "),_("p",[v._v("走过西伯利亚，回到东北的尽头。到呼伦贝尔之东，兴安岭下的齐齐哈尔城里小住。扎龙湿地，万千白鹤齐舞；嫩江之滨，多少鱼虾竟跃。但，万物之美，不改这满蒙边城之破败。再渡松花江，思心不减，感慨万千。南下奉天，忽昏沉倒下。昏昏然间，念及年来苦思，呕尽一切。淮阳何在？群芳何往？不必念想。一切已成往事，再不必追究。终到北平。帝都胜景，一如从前。举国人多如此，所爱岂止唯一？多病之时，不必求欢。且待将来，必有胜她之人。何苦为她，劳神苦思，满怀念想？于此地，调养身心。却不知，另有佳人，游于后海之畔。此行至此而终，南下渡江，重归金陵。一切已成往事，愿纵有再见之日，我仍安在，你亦安好。")]),v._v(" "),_("h2",{attrs:{id:"我心归处"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#我心归处"}},[v._v("#")]),v._v(" 我心归处")]),v._v(" "),_("p",[v._v("冬日的夜晚，荒凉的宣州。眼见着寒假的脚步一天天临近，回乡的车票，以及故乡这个词，越来越多的出现在了人们的口中。故乡是什么？故乡在哪里？迷茫如我，陷入了无边的沉思。十几年间，心，仿佛一直在中华大地漂泊。不知何处，才是我的故乡。")]),v._v(" "),_("p",[v._v("故乡，一重意味似乎是出生地。出生在雾都的我，在四岁那年又重返了雾都。于是，我记忆的起点，便发生在了雾都。雾都两载，似乎是我记忆里最快乐的日子。尽管体弱多病，但那许许多多的伙伴无处不在的关怀仍令我记忆犹新。居住于南坪，傍晚行走在长江之滨，看江上船来船往。徘徊于解放碑与朝天门，观雾都闹市盛景。横渡嘉陵江，到观音桥消暑驱热。上南山别墅小住，体验郊野生活。十年过去，雾都似已物是人非。再回首，可曾能再寻得昔日的回忆，唤起那些内心深处的美好？")]),v._v(" "),_("p",[v._v("故乡的另一重意味，则是长期生活过的地方，譬如金陵城之于我。但对于这座城市的记忆，却没有多少是美好的部分。去往雾都以前的日子的记忆早已模糊，而雾都归来的十年，却总难有几分愉悦的时光。自长江之头，至长江之尾，风土人情总是不同。金陵十载，失意于人心，便纵情于山水。寻遍城市的每一个角落，遇见那与众不同的她。从此，对金陵，有了那么些许感情。虽然，那些，多是伤感的回忆。在金陵城里，没有任何归属感，似乎只是个旅人，一个匆匆过客。")]),v._v(" "),_("p",[v._v("帝都，或许是我来往最频繁的城市。十一载，每一次到帝都，都是一番不同的情形。历史的厚重，让这座城庄严；帝都的荣耀，让这座城青春。繁华的一线城市，却没有另三座城那般的压力。开创下多了几分保守，进取中有着几分怀旧，这便是帝都。旧时代终结的残影，新时代开创的先兆。帝都，以博爱待世，让所有的伤痛化解。帝都，又不似江南多情，让许多故去的记忆重现。若是情伤难解，且到那里，把无尽的忧愁，化入历史的云烟。")]),v._v(" "),_("p",[v._v("我心归处即故乡。然心归何处，情将何往？看淡一切后，且在那大江南北，循着脚步，处处寻觅。时间与空间，无边无尽，更是无情。当时间所给予的伤痛缓缓平复，留下的，则是空间的茫然无措。金陵仍是那个金陵，帝都却已在记忆的海洋间缓缓变迁。十年未归的雾都，却又是如何一番面貌？也许，记忆早已消失殆尽，美好一律荡然无存。那些温暖的往事，那些美好的记忆，只能如花香般，在宣州这寒冷的夜里，放散着，那些温馨。")]),v._v(" "),_("p",[v._v("祖国的大西南，密布着丛山峻岭。云贵高原的山间，似乎是美好的去处。黔北的遵义，一个宜人的地方。远离尘嚣，明净安宁。可是，沉默不语的山水，可能够掩盖那一颗渴望红尘的心？如那通灵大峡谷的深处，通灵，却让人忍不住回味城市的喧嚣。而桂林，则是另外一般。山水虽美，尘世喧嚣却早已浸透，或有着几分山水的悦乐，也不过尔尔，终究还是难离城市的烦扰。山水，不在于本身，而在于人心。川北的若尔盖，青海的西宁，那里的山水，雄浑而壮阔，那是世界屋脊独有的，一种足以震撼人心的开阔。在那里，心，离天更近了一步，更远离了，世事烦忧。")]),v._v(" "),_("p",[v._v("世界屋脊之上，那最灿烂的明珠，莫过于圣城拉萨。海拔，让那里的阳光绚烂刺目。那里，有着湛蓝透明的高原天空，清流激湍的拉萨河。信仰，让藏民们，有着一切的无欲无求的超脱，让心，澄澈，呼应自然。无大喜，无大怒，无大哀，无大乐。脸上，总是神秘而淡然的微笑，满足于当下的日子。一部冈仁波齐，便述尽了他们的信仰与满足。在那里，真正忘记城市的喧嚣，淡化那心中一切的复杂的难舍的心结。")]),v._v(" "),_("p",[v._v("自那世界屋脊之下，黄河咆哮着东流。她滋养着华夏，哺育着，那中原的儿女。长江比起黄河，太柔了几分。黄河，是战斗的，是刚毅的。金城兰州，那浑黄的河水里船只往来穿梭。风吹浪打，动人心魄。大铁桥上的落日，照耀着这千载黄河的今生。郑州城外，渡浮桥，黄河一阵阵拍打着，车身摇曳，心惊胆寒。然而终究，这属于中原汉子的豪迈，着落在了那历史悠久的西安城中。历史的气息，混合着黄土，扑面而来。那里，有着秦时的明月，有着汉室的离乱，有着盛唐的气象，照着华夏的余晖。历史，太厚重，压的人喘不过气。但在那秦岭之下的神农架，则会令人感到发自内心的惬意。茫茫林海，野人的传说回荡；蓝天白云，是都市里难觅的清心。寡欲，便得以抛下许多。可是剩下的，便只留了执念。一条秦岭，两重华夏。向北，是历史；向南，是江湖。")]),v._v(" "),_("p",[v._v("穿越华夏大地，将视线投向那遥远的北疆。工业时代的沧桑，停留在那已不肥沃的黑土地上。人，渐渐远去了；自然，一步步地归来。扎龙湿地万千鹤舞，松嫩江畔鱼跃鸢飞。城市，因着人的减少而走向衰落，萧瑟的自然却又重新唤起了生机。大兴安岭的另一边，是茫茫的蒙古草原。草原八月，油菜花开，正是风光最曼妙的时节。呼伦贝尔的阳光，同样照耀着远处的西伯利亚。心胸开阔，觉天地如一。山自山，川自川。苦自苦，爱自爱，何必挂怀？世界，不因人的改变而改变。爱情，不因心的不灭而不灭。该消却的，无论时隔几载，终究还是会灭绝。")]),v._v(" "),_("p",[v._v("环绕着中国的，是海。北边的尽头，是中国的内海渤海边上的小城，秦皇岛。一边临山，一边靠海，让这座城有着独特的战略意义。总是弥漫在河北上空挥之不去的雾霾，在这里已悄然销声匿迹。渤海的景色还是美的，而到了大连，迈入黄海，那水色便不再碧蓝，而是多了属于那黄土高原的气息。青岛和大连，相似却又不同。大连更多的是浪漫，青岛更多的是悠闲。然而中国最美的海，终究还是南海。北部湾边的小城北海，有着属于小城市的幽静自在；海南岛上的旅游圣地三亚，也是一种熙熙攘攘市井气息的安宁。琼州海峡的日出，更是美妙绝伦。但，这一切的中心，着落在了，那繁忙的广州城。熙熙攘攘的人群充斥这里，肤色各异的人们拥塞此地。自古以来，这里，便是投机者的猎场，冒险家的乐园。广州，驻留不如离去。")]),v._v(" "),_("p",[v._v("然而，在那闽东南的一隅。厦门，那遗世独立的海岛，既有着尘世的喧嚣，亦有着世外的安静。黄厝海滨，椰风寨旁，曾厝垵下，厦大白城，厦门的海景，唯美，动人。南普陀寺，文曾路边，白鹭洲头，鼓浪屿上，清幽，静谧。城市之中，繁华之处尽显那都市的盛景。城市之外，大海之滨全是那无边的湛蓝。在这美丽的小城里，最美的风景，是人。粤语，表现的是男子的刚毅与热血；而闽南话，则表达的是女子的委婉与温柔。闽南话是柔柔的，而闽南的女子，似乎也是柔柔的。浪漫之城，有着，浪漫的姑娘。")]),v._v(" "),_("p",[v._v("一切的最后，回到身处的江南。所谓江南的美好，或许，并不如那所描述的一般真实。商业化，让那无数的古镇，失去了它们应有的味道。唯有苏州，这座最能代表江南的城，保留了江南的古韵，更有着现代的气息。上海滩的喧嚷，映在了那观前街的人流如织中；天平山的清净，护住那木渎古镇的古韵悠长。在苏州，美食无处不在，园林四处可寻。长江，流过张家港，常熟与太仓；太湖，环抱着吴中，虎丘与吴江。两水相依，让苏州，有着似水的温柔。吴侬软语，昆曲婉转。恋一座城，爱，这里的人。温柔的女孩，去了这里，融在，这美丽的城中。清丽的姑娘，离开这里，带来，那水乡的风采。人世的苦痛不外乎贫穷疾病孤独死亡，抑或是爱欲不能圆满。而在那太湖之滨的古村，村口的大槐树下，却觉得这一切顿时消散。回归心灵的净土，少想物欲的沉沦。境界，或许便不一样了 。江南，水乡，天堂。这份荣光，只应姑苏独享。")]),v._v(" "),_("p",[v._v("遍历华夏，何处故乡？心归无处，自是故乡无寻。可是雾都？可是姑苏？可是鹭岛？可是帝都？神州大陆，唯钟四处。情归于雾都，心牵于姑苏；魂定于鹭岛，梦留于帝都。然命运无常，奈何纷乱。谁道此处，仍是当年模样？不思，不想。且自修心情，若至超然物外之境，任凭往事随风，一切成空，那么甚好。")]),v._v(" "),_("h2",{attrs:{id:"再无思慕"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#再无思慕"}},[v._v("#")]),v._v(" 再无思慕")]),v._v(" "),_("p",[v._v("寒假的岁月，在怠惰的时光中渐渐逝去；金陵的时光，在银白的记忆里模糊不清。时隔半年再到帝京，却早已不复曾经。那时熟识的人们，已经离我远去，无处找寻。那时陌生的人们，却渐渐走入了我的生活，从天南海北来到一起。那时的奉天街头，英俊的小伙，也许曾有照面，但谁能知晓那日后，得以一见投缘？那时的后海街角，漂亮的姑娘，也许曾有擦肩，但素不相识的你我，怎知日后重又相见？新年将至，再不必怀念过往，是时候翻开新的一页。")]),v._v(" "),_("p",[v._v("从前的日色变得慢，车、马、邮件都慢，一生只够爱一个人。但那别离的旅人，也许一世都再难得相见。如今时代变迁，纵使大洋彼岸也不过半日的距离。但缘尽的人啊，纵使离得再近也难得相见，纵使人群擦肩也不复从前。她的十八岁终究谢幕了，有幸在那她人生中最美好的三载时光中，遇上了美丽的她。一切，此时终结；一切，今朝谢幕。帝都，新旧交融，古朴的深宅大院，现代的艺术风景。多少人来去匆匆，多少人心归无处？后海街头，已没有了佳人的痕迹；金陵城里，已寻不到伊人的影踪。往事已矣，新年将至。只愿那前方的路途，再无思慕。")]),v._v(" "),_("h2",{attrs:{id:"江南水乡"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#江南水乡"}},[v._v("#")]),v._v(" 江南水乡")]),v._v(" "),_("p",[v._v("曾经，有过那一个属于江南的梦。然而，这突如其来的四月之旅，却让那美好的梦境，化为一个个五彩的肥皂泡。破碎了，便一去不复返了。")]),v._v(" "),_("p",[v._v("那美好梦境的主角，便是，那姑苏城，那我曾认为，最能代表江南的城。然而，来自上海滩的喧嚷，已盖过了曾经美好的一切。形犹如此，而神已不再。正如那长大成人的女孩，虽然漂亮的外表依然如故，但不复存在的，是曾经眼神中那干净与清纯。")]),v._v(" "),_("p",[v._v("长江与太湖的两水相依，让苏州，有着似水的温柔。吴侬软语，昆曲婉转。这是曾经梦里天堂般的江南水乡，这是那理应只由姑苏独享的荣光。但如今，婉转与温柔犹在，可那只是矫揉造作的饰品。姑苏，已不复天堂。")]),v._v(" "),_("p",[v._v("人世的苦痛不外乎贫穷疾病孤独死亡，抑或是爱欲不能圆满。曾经那太湖之滨的古村，村口的大槐树下，能让这一切顿时消散。使人回归心灵的净土，不再去想物欲的沉沦。但如今衰败中夹杂着商业气的古村，已不再是能让心灵平静的地方。当天平山已不再寂静，木渎古镇便只剩下了，喧嚣无尽。")]),v._v(" "),_("p",[v._v("已经没有多少再值得爱慕，没有多少再值得怀念。梦碎时分，江南不再。忘却属于这一座城的梦，忘却属于这梦里的一个个人。那融入在这梦里的温柔女孩，已淡却在记忆里；那从这梦中走出的清丽姑娘，却仍使我迷茫着。")]),v._v(" "),_("p",[v._v("曾经，这是我心心念念的姑苏，悠然神往的江南。现在，她只是苏州，一个有着清丽外表的现代之城。梦，破碎了。而何处，是前方？")]),v._v(" "),_("h2",{attrs:{id:"西南风月"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#西南风月"}},[v._v("#")]),v._v(" 西南风月")]),v._v(" "),_("p",[v._v("桂林，一座温柔的城市。山与水相依，江与湖共舞。行走间尽是装点的精致，却也仍免不了留下岁月的痕迹。也许她曾是个清秀的少女，但如今她却已渐渐老去。浓妆艳抹的脂粉气息粉饰出她曾经的雍容华美，穿金戴银的奢华装扮掩饰着她此时的饱经风霜。她，是最早的网红，有着让千万游人沉醉的山水，有着那无数赞不绝口的评价。如今的她，已经充满了世俗气。鲜艳夺目，却已不复当年纯情。")]),v._v(" "),_("p",[v._v("当和谐号CRH2A动车组的白光跨越黔桂边界的崇山峻岭，大山深处的黔南，便浮现在了眼前。纵使晴空万里，也会忽然下起暴风雨，但待到云开雾散，又是一片蓝天白云的风景。都柳江畔三都小城，樟江沿岸荔波古镇。山与水的交融，仁与智的交锋。仁者乐山，智者乐水，大贤无为山水。恪守山的谨严，谨守有形或无形的规则。追寻水的自由，放飞真实或虚妄的自我。大音希声，大象无形，道隐无名。")]),v._v(" "),_("p",[v._v("贵州的雨，一刻不停。一朵乌云就是一片雨，一缕阳光照亮一片天。海拔一千米的黔中，让这个火热的夏日瑟瑟地寒凉。云青青兮欲雨，水澹澹兮生烟。难逢的蓝天，飞湍的瀑流，还有雨，还有风。不求像风一样自由，但愿如水一般洒脱。爱了就是爱了，恨了就是恨了，放下了就是放下了，忘却了就是忘却了。心灵放空，百念既除。")]),v._v(" "),_("p",[v._v("彩云之南，那梦一般的地方。迷蒙的天气，幻化的心情。阳光有一阵没一阵，洒落滇池畔的昆明。水是一汪碧绿，天是一抹清新。距离愈行愈远，心灵愈走愈清。变幻莫测的天气，纷扰了心情。光怪陆离的梦境，模糊了过去。想带你去看星空万里，想大声告诉你我为你着迷。但，往后的一生，不可能是你。把别人看得太重，却把自己看得太轻。时光匆匆，却没有往事；来来往往，也没有感动。再多的说辞都是借口，再多的言语不过说说。单恋，也许是更大的快乐。")]),v._v(" "),_("p",[v._v("丽江，那云贵高原之上离天空咫尺之遥的地方。碧蓝的天空与碧蓝的幻想，投影在那古城的斑驳里。一座山，一条河，石板路的青苔与水车。酒吧的夜夜笙歌，茶社的清静无为。去一棵树下，感受时间的流逝；去一座山上，体会古韵的春秋。雪山不远，藏区也不远。云贵高原的小城，却有着几分雪域高原的味道，也许，这便是这里浪漫风韵的缘由吧。七夕过了，又是一年散发着单身狗清香气息的时光。放下幻想，不怀期望。")]),v._v(" "),_("p",[v._v("苍山，洱海。一个在云端，一个是深蓝。爱雾绕的山，恋梦幻的水，却不喜欢，那山海交际的城。古韵的记忆消失在梦里，现实的山水消散在人群。只剩，三塔，佛门，还有那一条流过古城的溪。并非每一种不知所起的情，都值得一往而深。喜欢她，念着她，纵不再相遇，亦不负深情。")]),v._v(" "),_("h2",{attrs:{id:"雪落无声"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#雪落无声"}},[v._v("#")]),v._v(" 雪落无声")]),v._v(" "),_("p",[v._v("没有目标的旅途，随心所欲的行动，抛下所有牵挂和束缚。即刻出发，风霜雨雪间看凌晨四点西子湖畔灯光点点。总有惊喜，雪花飘飘里观外滩上下城隍庙间魔都风情。梦里水乡，姑苏内外走过甪直古镇观前繁华山塘热闹。漂泊的时光里，释放那不羁的灵魂。单调的岁月里，需要那放纵的旅程。茫茫大雪之中，不求谁能回顾，不问初心何处。只不负自己，便是极好。")]),v._v(" "),_("p",[v._v("还依稀记得那句：或许不知梦的缘故，流离之人追逐着幻影。不知梦的人，流离着，追逐着一片又一片的幻影。忘却了过往，也迷失了心情。迷茫和混沌是2018的主旋律，在群聊里丢弃了自我，方寸荧屏抽尽了灵魂。如吸毒成瘾，戒不去，消不得。")]),v._v(" "),_("p",[v._v("飘渺的感情不知归宿，只不过是灵感的来由。再也写不出那些词句，只因失却那份心情。划地三尺只为转世灵魂换你的生辰，诵一段因果，结来世的红绳。宿命注定的，相聚相散，相合相分。月光偷偷打量，可怜缘分，岁月的年轮，再诚恳，也渡不过红尘。相识是幸运，离别是宿命，莫去强求。")]),v._v(" "),_("p",[v._v("真正彻彻底底的将心置空，容不下任何身影。不曾有过喜欢人的能力，在疯狂中放纵自己。因一个人，爱一座城，又厌一座城。直至故事的最后，却重又恋上这座城。一座古镇，一条小河，沉淀了记忆，放松了心灵。午后，似晴似阴的时光里，漫步在青石板路上，身旁是小桥流水，渐忘却了时光。")]),v._v(" "),_("p",[v._v("不曾喜欢现代的奢华，偏爱那份古典的优雅。不再相信一见钟情的童话，也不会去迷恋任何有趣的灵魂。也许依然有喜欢的人，但，已与我无关。忆起上海滩的那一场大雪，下得那么深，下得那么认真……")]),v._v(" "),_("h2",{attrs:{id:"孔明灯下"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#孔明灯下"}},[v._v("#")]),v._v(" 孔明灯下")]),v._v(" "),_("p",[v._v("芜湖滨江，孔明灯的盛放，给不务正业的三下乡，画上了美丽的逗号。江城的夜色，在辉映的梦里凄美地绚烂。烦闷的大二时光即将落幕，不再做情的想，爱的梦。回到原点的从前，珍惜每一段相遇，让宿命的年轮倾倒。月如银盘，点点是明珠的多彩，珍惜前缘的过往，疏解无望的心房。夜深处，应当再见的，是无所处的想。")]),v._v(" "),_("h2",{attrs:{id:"粤海迷思"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#粤海迷思"}},[v._v("#")]),v._v(" 粤海迷思")]),v._v(" "),_("p",[v._v("最近经常做噩梦，可能是因为太长时间没有过过相对规律的生活了，一旦闲下来就很容易各种各样的胡思乱想。现实中许多的焦虑，总在夜里浮上心头。我曾以为，因一个人而爱一座城的盲目与我无关，直到她的出现让我产生了不切实际的妄想。但又当我以为我已经决定了向往的地方，现实却又浇醒了虚弱的迷茫。那日的匆匆一见，又埋下了另一颗幻境的种子。倘若追逐梦幻而去，又能有什么收获呢？")]),v._v(" "),_("p",[v._v("人事的一切纷纭，都是些说不清也道不明的东西。谁也预料不到未来会发生什么，就像十天前沉浸在过年气氛中的人们想不到，新春佳节会因一场突如其来的疫情而变得冷冷清清。开学或许将要推迟，美赛确定已经推后，本就波澜诡谲的智能车也因着这突如其来的事件而更加难以预知。所有的计划在变化的面前都不值一提，所有的激情在未知面前退缩成恐惧。")]),v._v(" "),_("p",[v._v("所谓的喜欢，想支撑一个人走下去并不容易。喜欢是刹那的心动，心动是一瞬的花火。一瞬的花火，可以短暂照亮一片心空，却不能点燃整个世界。就像我以为我喜欢的是计算机，其实我只是喜欢简单的0和1。一瞬间的心动就像是一瞬间的信号1，打开了紧扣心扉，点燃了心中的花火。可随着信号结束，火光总会熄灭，热情化于沉寂。也许，这就是心动的感觉。")]),v._v(" "),_("p",[v._v("爱情公寓完结了，凌晨四点的洛杉矶完结了，记忆里的青春也完结了。再见，一零年代。你好，二零年代。虽然这个开局的月份里有着太多悲伤与无奈，但我们相信，一切会好起来。")]),v._v(" "),_("p",[v._v("2月13日，大雨，有雷电。记忆的闸门猛然打开，往日的故事终究可以付诸笔下。那生命里短暂的过客，终究在时光的洗礼间消失无影，只留下，一点残破的记忆。")]),v._v(" "),_("p",[v._v("记忆的起点，应当是五年前的冬天吧。在那时，他是那数学的王者，她则是数学的弃儿，他们的数学成绩之和刚刚够得到满分。偶然之下他们结识，他为她补习数学，她为他补习英语。眼见她的数学有了起色，英语却跌到了与他一般的水平。不知什么时候，他对她有了莫名的好感，但随之而来的，却是分班的时刻。")]),v._v(" "),_("p",[v._v("顺理成章地，他去了理科班，她去了文科班。繁重的学习压力下，他无暇他顾，可还是会时不时关注她，打听她的消息。也曾跨过半个城市，只为期待她的出现。听说，她有了男票，有了自己的生活。他终于意识到，他们之间，就如同那高考分数的鸿沟难以逾越，只能祝愿她，前程似锦，余生幸福。")]),v._v(" "),_("p",[v._v("淮水之阳，她的故乡，一望成欢，即是淮阳。两年之前，似是今日，又是明日，也无妨，终究是放下了。非是故事，也不值得。既然已经离开了那座城市，一切，说不定会好起来。")]),v._v(" "),_("p",[v._v("当他初遇那山间的小城时，便被那靓丽的绝色惊艳了。她像一颗璀璨的明珠，吸引着无数的追求者，也让更多的人望而却步。当先前的一切尽数放下，那个春天里，他不禁动了心思。可随之而来的，是一道艰难的选择题。斟酌之后，他选择了离开，让所有的花火随着转专业而熄灭。误会逐渐产生和蔓延，却也不曾想要解释，这或许便是放弃的代价。后来，没有了后来，一切的一切，不过是罪有应得。")]),v._v(" "),_("p",[v._v("大雨如注。又是一年冬天，为一个偶然相遇的人而改变了选择，这又是否值得？")]),v._v(" "),_("p",[v._v("当世界陷于了沉寂，春天的到来也变得悄无声息。停滞的岁月里，今天与明天毫无区别，一切的一切索然无趣。未可名的现在，不可知的未来。白色恐怖下的天地里少了一方烟火气，人烟消散了，城市也不再有着城市的模样。只剩了碧海和蓝天，和空空荡荡的大街小巷。")]),v._v(" "),_("p",[v._v("果实熟透了，吃了才不会生病。时机成熟了，努力才不会白费。昔日若是没有迈出那步，也许境遇便大有不同。选择了一条比较艰难的路，便要学会接受路上的一切。不论是好是坏，是苦是累。纵使有更好的选择，也要把这条路走过。尽管，未来很可能会去后悔。")]),v._v(" "),_("p",[v._v("一个人真正想要什么，不取决于他说了些什么，而取决于他做了些什么。面对目标，谁先低头谁就输了。也许当初的高考分数在考研面前显得卑微，也许自身的能力在理想面前显得狼狈，但这都没有关系。为了心中的那一片美好而奋斗，即使输到一无所有，也值得。")]),v._v(" "),_("p",[v._v("明天，不曾开学，却将开始上课。一切陌生而不适即将发生，一切的一切...就像爱情，也许会在某个无法预知的时机来临吧。")])])}),[],!1,null,null,null);_.default=s.exports}}]);